      (function () {
        var MAX_RETRIES = 12;
        var RETRY_DELAY = 350;

        function getPlayableAudio() {
          var byId = document.getElementById('bgMusic') || document.getElementById('background-music');
          if (byId) return byId;

          var audios = document.querySelectorAll('audio');
          for (var i = 0; i < audios.length; i++) {
            var audio = audios[i];
            if (audio.getAttribute('src')) return audio;
            var source = audio.querySelector('source');
            if (source && source.getAttribute('src')) return audio;
          }
          return null;
        }

        function updateMusicIcon(isPlaying) {
          var playIcon = document.getElementById('play-icon');
          var pauseIcon = document.getElementById('pause-icon');
          if (playIcon) playIcon.style.display = isPlaying ? 'none' : 'block';
          if (pauseIcon) pauseIcon.style.display = isPlaying ? 'block' : 'none';
        }

        function tryPlayMusic() {
          var audio = getPlayableAudio();
          if (!audio) return Promise.resolve(false);

          audio.muted = true;
          if (!audio.getAttribute('playsinline')) {
            audio.setAttribute('playsinline', '');
          }

          var playPromise = audio.play();
          if (playPromise && typeof playPromise.then === 'function') {
            return playPromise.then(function () {
              setTimeout(function () {
                audio.muted = false;
              }, 200);
              updateMusicIcon(true);
              return true;
            }).catch(function () {
              audio.muted = false;
              updateMusicIcon(false);
              return false;
            });
          }

          setTimeout(function () {
            audio.muted = false;
          }, 200);
          updateMusicIcon(!audio.paused);
          return Promise.resolve(!audio.paused);
        }

        function tryPlayWithRetry(attempt) {
          return tryPlayMusic().then(function (ok) {
            if (ok) return true;
            if (attempt >= MAX_RETRIES) return false;

            return new Promise(function (resolve) {
              setTimeout(function () {
                resolve(tryPlayWithRetry(attempt + 1));
              }, RETRY_DELAY);
            });
          });
        }

        function registerInteractionFallback() {
          var fired = false;
          var events = ['pointerdown', 'touchstart', 'click', 'scroll', 'keydown'];

          function onFirstInteraction() {
            if (fired) return;
            fired = true;
            events.forEach(function (name) {
              window.removeEventListener(name, onFirstInteraction, true);
            });
            tryPlayMusic();
          }

          events.forEach(function (name) {
            window.addEventListener(name, onFirstInteraction, { once: true, capture: true, passive: true });
          });
        }

        setTimeout(function () {
          tryPlayWithRetry(0).then(function (ok) {
            if (!ok) registerInteractionFallback();
          });
        }, 0);
      })();
